//! `skychat` — a sovereign skychat client, admitted into the moonshine shell as its OWN binary
//! (resolved from `.bin/skychat` like `moonbeam`/`rip`), not a subcommand baked into `moonshine`.
//!
//! Interactive TUI by default; `--oneoff` / `--send` give a bounded, non-interactive one-shot for
//! agents and scripts. The shell admits this binary; agents can also call it directly on the CLI.
use anyhow::Result;
use clap::Parser;
use moonshine::skychat_tui;

#[derive(Parser)]
#[command(
    name = "skychat",
    about = "skychat — CRDT community chat. Interactive TUI, or --oneoff for bounded agent use."
)]
struct Cli {
    #[arg(default_value = "general", help = "Room/channel id to join")]
    room: String,
    #[arg(short, long, help = "Your nick / DID in the room")]
    nick: Option<String>,
    #[arg(
        long,
        default_value = "https://skychat.forkjoin.ai",
        help = "skychat worker base URL (http/https)"
    )]
    base: String,
    #[arg(
        long,
        help = "Non-interactive: print recent messages (and optionally --send) then exit — bounded output for agents"
    )]
    oneoff: bool,
    #[arg(
        long,
        value_name = "MESSAGE",
        help = "Post this message then exit (implies non-interactive); add --oneoff to also print recent"
    )]
    send: Option<String>,
    #[arg(long, default_value_t = 20, help = "Non-interactive: how many recent messages to print")]
    limit: usize,
    #[arg(long, help = "Non-interactive: emit messages as JSON instead of text")]
    json: bool,
}

fn resolve_nick(explicit: Option<String>) -> String {
    explicit
        .or_else(|| std::env::var("SKYCHAT_NICK").ok())
        .or_else(|| std::env::var("MOONSHINE_DID").ok())
        .or_else(|| std::env::var("USER").ok())
        .map(|n| n.trim().to_string())
        .filter(|n| !n.is_empty())
        .unwrap_or_else(|| "anon".to_string())
}

#[tokio::main]
async fn main() -> Result<()> {
    let cli = Cli::parse();
    let nick = resolve_nick(cli.nick);
    if cli.oneoff || cli.send.is_some() {
        skychat_tui::run_oneoff(&cli.base, &cli.room, &nick, cli.send.as_deref(), cli.limit, cli.json).await
    } else {
        skychat_tui::run(&cli.base, &cli.room, &nick).await
    }
}
